#Requires -Version 5.1
<#
.SYNOPSIS
    Sel01-Tweaker - one-click, unattended Windows 11 debloat + performance optimizer.
.DESCRIPTION
    Runs a single pass: debloat, AI removal, native tweaks, performance/visual
    effects, power plan, gaming + FiveM tweaks, and a native RAM cleaner.
    Creates a System Restore point and a per-value registry backup (-Revert).

    No -Profile  -> interactive console menu (overview + confirm before running).
    -Profile X   -> runs that profile directly (for the irm|iex one-liner).
.EXAMPLE
    .\Sel01Tweaker.ps1                 # interactive menu
.EXAMPLE
    & ([scriptblock]::Create((irm https://URL/Sel01Tweaker.ps1))) -Profile Gaming
.EXAMPLE
    .\Sel01Tweaker.ps1 -Revert
#>
[CmdletBinding()]
param(
    [ValidateSet('Gaming','Clean','')]
    [string]$Profile = '',
    [switch]$Revert,
    [switch]$NoRestore,
    [switch]$SkipDebloat,
    [switch]$SkipAI,
    [switch]$SkipFiveM,
    [switch]$NoRamTask,
    [switch]$DryRun
)

# ============================================================================
#  Sel01Tweaker - bundled distribution (generated by build.ps1; do not edit by hand)
#  One-click Windows 11 debloat + performance optimizer.
#  Source: src\  |  Run: .\Sel01Tweaker.ps1 -Profile Gaming   (auto-elevates)
# ============================================================================
# ----- bundled: Common.ps1 -----
# ============================================================================
#  Sel01Tweaker - lib/Common.ps1
#  Shared helpers: state, logging, registry (typed + snapshot), P/Invoke,
#  remote-script orchestration, preferences-mask builder.
#  All modules dot-source this file and share $Global:Sel01Tweaker state.
# ============================================================================

# ---------------------------------------------------------------------------
#  Global state (initialised by Sel01Tweaker.ps1, but guarded here so modules can be
#  dot-sourced and unit-tested in isolation).
# ---------------------------------------------------------------------------
if (-not $Global:Sel01Tweaker) {
    $Global:Sel01Tweaker = [ordered]@{
        Profile   = 'Gaming'
        DryRun    = $false
        DataDir   = (Join-Path $env:ProgramData 'Sel01Tweaker')
        LogFile   = $null
        BackupFile= $null
        Backup    = [System.Collections.Generic.List[object]]::new()
        Changes   = [System.Collections.Generic.List[string]]::new()
        RebootNeeded = $false
        SkippedCount = 0
        IsWin11   = $true
        OSBuild   = 0
        OSName    = 'Windows'
    }
}

function Get-Sel01OSInfo {
    <#  Detects Windows 10 vs 11. [Environment]::OSVersion reports 10.0.x for
        BOTH, so we use the build number: Win11 = build >= 22000. ProductName
        also lies ("Windows 10" on 11), so the friendly name is derived from
        the build + DisplayVersion.  #>
    $cv = 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion'
    $build = 0
    try { $build = [int](Get-ItemProperty $cv -Name CurrentBuildNumber -ErrorAction Stop).CurrentBuildNumber } catch {}
    if ($build -eq 0) { try { $build = [Environment]::OSVersion.Version.Build } catch {} }
    $disp = ''
    try { $disp = (Get-ItemProperty $cv -Name DisplayVersion -ErrorAction Stop).DisplayVersion } catch {}
    $isWin11 = ($build -ge 22000)
    $Global:Sel01Tweaker.IsWin11 = $isWin11
    $Global:Sel01Tweaker.OSBuild = $build
    $Global:Sel01Tweaker.OSName  = ('Windows {0}{1}' -f ($(if ($isWin11) {'11'} else {'10'})), $(if ($disp) {" $disp"} else {''}))
    return $Global:Sel01Tweaker.OSName
}

function Initialize-Sel01TweakerState {
    <#  Creates the data dir and timestamped log/backup file paths.
        Timestamp is passed in (Date.now-style calls are avoided in scripted
        contexts; the entry point supplies it).  #>
    param([string]$Stamp)
    if (-not (Test-Path $Global:Sel01Tweaker.DataDir)) {
        New-Item -ItemType Directory -Path $Global:Sel01Tweaker.DataDir -Force | Out-Null
    }
    $Global:Sel01Tweaker.LogFile    = Join-Path $Global:Sel01Tweaker.DataDir "log-$Stamp.txt"
    $Global:Sel01Tweaker.BackupFile = Join-Path $Global:Sel01Tweaker.DataDir "backup-$Stamp.json"
}

# ---------------------------------------------------------------------------
#  Logging
# ---------------------------------------------------------------------------
function Write-Log {
    param(
        [Parameter(Mandatory)][string]$Message,
        [ValidateSet('INFO','WARN','ERROR','OK','STEP')][string]$Level = 'INFO'
    )
    $line = "[$Level] $Message"
    $color = switch ($Level) {
        'OK'    { 'Green' }
        'WARN'  { 'Yellow' }
        'ERROR' { 'Red' }
        'STEP'  { 'Cyan' }
        default { 'Gray' }
    }
    Write-Host $line -ForegroundColor $color
    if ($Global:Sel01Tweaker.LogFile) {
        Add-Content -Path $Global:Sel01Tweaker.LogFile -Value $line -Encoding UTF8
    }
}

function Add-Change {
    param([string]$Text)
    $Global:Sel01Tweaker.Changes.Add($Text) | Out-Null
}

# ---------------------------------------------------------------------------
#  Admin / elevation
# ---------------------------------------------------------------------------
function Test-Admin {
    $id = [Security.Principal.WindowsIdentity]::GetCurrent()
    $p  = New-Object Security.Principal.WindowsPrincipal($id)
    return $p.IsInRole([Security.Principal.WindowsBuiltinRole]::Administrator)
}

# ---------------------------------------------------------------------------
#  Network guard (for orchestrated downloads)
# ---------------------------------------------------------------------------
function Test-Online {
    try { return (Test-Connection -ComputerName 'github.com' -Count 1 -Quiet -ErrorAction Stop) }
    catch { return $false }
}

# ---------------------------------------------------------------------------
#  Registry helpers
# ---------------------------------------------------------------------------
function Get-RegValueSafe {
    <#  Returns @{ Exists=$bool; Value=...; Kind=[Microsoft.Win32.RegistryValueKind] }
        Works on a PS-provider path like 'HKCU:\Software\Foo'.  #>
    param([string]$Path,[string]$Name)
    $result = @{ Exists = $false; Value = $null; Kind = $null }
    if (-not (Test-Path $Path)) { return $result }
    $item = Get-ItemProperty -Path $Path -Name $Name -ErrorAction SilentlyContinue
    if ($null -eq $item) { return $result }
    # Resolve the real RegistryValueKind via the .NET key.
    try {
        $rk = Get-Item -Path $Path -ErrorAction Stop
        $kind = $rk.GetValueKind($Name)
        $result.Exists = $true
        $result.Value  = $rk.GetValue($Name)
        $result.Kind   = $kind
    } catch {
        $result.Exists = $true
        $result.Value  = $item.$Name
    }
    return $result
}

function Test-RegValueEqual {
    <#  True when an existing registry value already equals the target, so the
        write can be skipped (idempotency - never re-force what's already set).
        Normalises DWORD to uint32 so e.g. 0x80000001 (stored as int32 -2147...)
        compares equal to the long literal.  #>
    param($Current,[string]$Type,$Target)
    switch ($Type) {
        'Binary' {
            $a = [byte[]]$Current; $b = [byte[]]$Target
            if ($a.Length -ne $b.Length) { return $false }
            for ($i=0; $i -lt $a.Length; $i++) { if ($a[$i] -ne $b[$i]) { return $false } }
            return $true
        }
        'DWord' { return ((([int64]$Current) -band 0xFFFFFFFF) -eq (([int64]$Target) -band 0xFFFFFFFF)) }
        'QWord' { return ([int64]$Current -eq [int64]$Target) }
        'MultiString' { return ((@($Current) -join "`0") -eq (@($Target) -join "`0")) }
        default { return ([string]$Current -eq [string]$Target) }   # String / ExpandString
    }
}

function Set-Reg {
    <#  The single typed registry-write entry point used by every module.
        - If the value is ALREADY correct, skips (no snapshot, no write, no
          change recorded) so re-runs don't re-force settings you already have.
        - Otherwise snapshots the prior value BEFORE writing (enables -Revert).
        - Honours DryRun (logs intent, writes nothing).
        - Handles String / ExpandString / DWord / QWord / Binary / MultiString.
        $Value for Binary must be a byte[].  #>
    param(
        [Parameter(Mandatory)][string]$Path,
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][ValidateSet('String','ExpandString','DWord','QWord','Binary','MultiString')]
        [string]$Type,
        [Parameter(Mandatory)]$Value,
        [string]$Note
    )

    $prior = Get-RegValueSafe -Path $Path -Name $Name

    # --- Idempotency: already correct? skip entirely ----------------------
    if ($prior.Exists -and ("$($prior.Kind)" -eq $Type) -and (Test-RegValueEqual $prior.Value $Type $Value)) {
        $Global:Sel01Tweaker.SkippedCount++
        Write-Log "schon ok, skip: $Path\$Name" 'INFO'
        return
    }

    # Record snapshot once per (Path,Name) so first-seen original wins.
    $already = $Global:Sel01Tweaker.Backup | Where-Object { $_.Path -eq $Path -and $_.Name -eq $Name }
    if (-not $already) {
        $snap = [ordered]@{
            Path    = $Path
            Name    = $Name
            Existed = $prior.Exists
            OldType = if ($prior.Kind) { "$($prior.Kind)" } else { $null }
            OldValue= if ($prior.Exists) { $prior.Value } else { $null }
        }
        $Global:Sel01Tweaker.Backup.Add([pscustomobject]$snap) | Out-Null
    }

    $display = if ($Type -eq 'Binary') { ($Value | ForEach-Object { '{0:X2}' -f $_ }) -join ' ' } else { "$Value" }
    $label = "$Path\$Name = $display ($Type)"

    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log "DRYRUN reg: $label" 'INFO'
        return
    }

    try {
        if (-not (Test-Path $Path)) { New-Item -Path $Path -Force | Out-Null }
        New-ItemProperty -Path $Path -Name $Name -PropertyType $Type -Value $Value -Force | Out-Null
        Write-Log "reg: $label" 'INFO'
        if ($Note) { Add-Change $Note }
    } catch {
        Write-Log "reg FAILED: $label -> $($_.Exception.Message)" 'WARN'
    }
}

function Remove-Reg {
    <#  Deletes a value; snapshots first so revert can re-create it.  #>
    param([string]$Path,[string]$Name,[string]$Note)
    $prior = Get-RegValueSafe -Path $Path -Name $Name
    # Idempotency: nothing there -> nothing to remove.
    if (-not $prior.Exists) { $Global:Sel01Tweaker.SkippedCount++; Write-Log "schon weg, skip: $Path\$Name" 'INFO'; return }
    $already = $Global:Sel01Tweaker.Backup | Where-Object { $_.Path -eq $Path -and $_.Name -eq $Name }
    if (-not $already) {
        $Global:Sel01Tweaker.Backup.Add([pscustomobject]@{
            Path=$Path; Name=$Name; Existed=$prior.Exists
            OldType= if ($prior.Kind) { "$($prior.Kind)" } else { $null }
            OldValue= if ($prior.Exists) { $prior.Value } else { $null }
        }) | Out-Null
    }
    if ($Global:Sel01Tweaker.DryRun) { Write-Log "DRYRUN reg-del: $Path\$Name" 'INFO'; return }
    if ((Test-Path $Path) -and $prior.Exists) {
        Remove-ItemProperty -Path $Path -Name $Name -Force -ErrorAction SilentlyContinue
        Write-Log "reg-del: $Path\$Name" 'INFO'
        if ($Note) { Add-Change $Note }
    }
}

# ---------------------------------------------------------------------------
#  Service start-type helper (used by winutil-tweak reimplementation)
# ---------------------------------------------------------------------------
function Set-ServiceStart {
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][ValidateSet('Boot','System','Automatic','Manual','Disabled')]
        [string]$StartupType,
        [string]$Note
    )
    # Map to the registry Start DWORD so snapshot/revert flows through Set-Reg.
    $map = @{ Boot=0; System=1; Automatic=2; Manual=3; Disabled=4 }
    $path = "HKLM:\SYSTEM\CurrentControlSet\Services\$Name"
    if (-not (Test-Path $path)) {
        Write-Log "service not present, skip: $Name" 'INFO'
        return
    }
    Set-Reg -Path $path -Name 'Start' -Type DWord -Value $map[$StartupType] -Note $Note
}

# ---------------------------------------------------------------------------
#  UserPreferencesMask builder
#  Deliberate per-byte construction of the "best performance" mask, keeping
#  font-smoothing / drag-full-window behaviour.  Documented value:
#  90 12 03 80 10 00 00 00
# ---------------------------------------------------------------------------
function Build-PreferencesMask {
    # byte0 0x90 = HotTracking(0x80) | GradientCaptions(0x10)
    # byte1 0x12 = TooltipFade(0x10)  | MenuFade(0x02)
    # byte2 0x03, byte3 0x80, byte4 0x10, bytes5-7 0x00  (Win "best performance")
    return [byte[]]@(0x90,0x12,0x03,0x80,0x10,0x00,0x00,0x00)
}

# ---------------------------------------------------------------------------
#  Broadcast WM_SETTINGCHANGE so UI picks up changes without sign-out.
# ---------------------------------------------------------------------------
function Broadcast-SettingChange {
    if ($Global:Sel01Tweaker.DryRun) { return }
    if (-not ([System.Management.Automation.PSTypeName]'Sel01Tweaker.Native').Type) {
        Add-Type -Namespace Sel01Tweaker -Name Native -MemberDefinition @'
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true, CharSet=System.Runtime.InteropServices.CharSet.Auto)]
public static extern System.IntPtr SendMessageTimeout(System.IntPtr hWnd, uint Msg, System.IntPtr wParam, string lParam, uint fuFlags, uint uTimeout, out System.IntPtr lpdwResult);
'@ -ErrorAction SilentlyContinue
    }
    try {
        $HWND_BROADCAST = [IntPtr]0xffff
        $WM_SETTINGCHANGE = 0x1A
        $res = [IntPtr]::Zero
        [void][Sel01Tweaker.Native]::SendMessageTimeout($HWND_BROADCAST, $WM_SETTINGCHANGE, [IntPtr]::Zero, 'Environment', 2, 5000, [ref]$res)
    } catch { Write-Log "Broadcast-SettingChange failed: $($_.Exception.Message)" 'WARN' }
}

function Restart-Explorer {
    if ($Global:Sel01Tweaker.DryRun) { Write-Log 'DRYRUN restart explorer' 'INFO'; return }
    try {
        Stop-Process -Name explorer -Force -ErrorAction SilentlyContinue
        # Windows auto-restarts explorer; start one if it didn't.
        Start-Sleep -Milliseconds 800
        if (-not (Get-Process -Name explorer -ErrorAction SilentlyContinue)) { Start-Process explorer.exe }
        Write-Log 'explorer restarted' 'INFO'
    } catch { Write-Log "explorer restart failed: $($_.Exception.Message)" 'WARN' }
}

# ---------------------------------------------------------------------------
#  Orchestration: download a remote script and invoke it with args.
#  Used by the Win11Debloat / RemoveWindowsAI modules (MIT, run as-is).
# ---------------------------------------------------------------------------
function Invoke-Remote {
    # Params is a hashtable splatted by NAME into the downloaded script. Use a
    # hashtable (not a flat -Flag array) so switch params bind reliably and
    # array params (e.g. RemoveWindowsAI -Options) pass as real arrays that pass
    # the script's ValidateSet element-by-element.
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][string]$Url,
        [hashtable]$Params = @{}
    )
    $shown = (($Params.GetEnumerator() | Sort-Object Name | ForEach-Object {
        if     ($_.Value -is [bool])  { "-$($_.Key)" }
        elseif ($_.Value -is [array]) { "-$($_.Key) $($_.Value -join ',')" }
        else                          { "-$($_.Key) $($_.Value)" }
    }) -join ' ')

    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log "DRYRUN orchestrate $Name : $Url $shown" 'INFO'
        return
    }
    if (-not (Test-Online)) {
        Write-Log "Offline - skipping $Name (needs download)" 'WARN'
        return
    }
    try {
        Write-Log "Downloading $Name ..." 'INFO'
        $code = Invoke-RestMethod -Uri $Url -UseBasicParsing -ErrorAction Stop
        $sb = [scriptblock]::Create($code)
        Write-Log "Running $Name $shown" 'INFO'
        & $sb @Params
        Write-Log "$Name finished" 'OK'
        Add-Change "$Name applied ($shown)"
    } catch {
        Write-Log "$Name failed: $($_.Exception.Message)" 'WARN'
    }
}


# ----- bundled: Backup.ps1 -----
# ============================================================================
#  Sel01Tweaker - lib/Backup.ps1
#  System Restore point creation, backup-JSON persistence, and -Revert.
#  Depends on Common.ps1 ($Global:Sel01Tweaker state, Write-Log, Set-Reg helpers).
# ============================================================================

function New-Sel01TweakerRestorePoint {
    <#  Ensures System Restore is enabled on the system drive, then snapshots.
        Windows rate-limits restore points to one per 24h by default; we relax
        that for this run so the checkpoint is guaranteed to take.  #>
    if ($Global:Sel01Tweaker.DryRun) { Write-Log 'DRYRUN restore point' 'INFO'; return }
    try {
        Write-Log 'Creating System Restore point...' 'STEP'
        Enable-ComputerRestore -Drive "$env:SystemDrive\" -ErrorAction SilentlyContinue
        # Relax the 24h frequency gate so the checkpoint is not silently skipped.
        Set-Reg -Path 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SystemRestore' `
                -Name 'SystemRestorePointCreationFrequency' -Type DWord -Value 0
        Checkpoint-Computer -Description 'Sel01Tweaker - before optimization' -RestorePointType 'MODIFY_SETTINGS' -ErrorAction Stop
        Write-Log 'Restore point created' 'OK'
    } catch {
        Write-Log "Restore point failed (continuing): $($_.Exception.Message)" 'WARN'
    }
}

function Save-Sel01TweakerBackup {
    <#  Writes the accumulated registry snapshots + run metadata to the backup
        JSON.  Called at the end of a run so -Revert has a manifest.  #>
    if ($Global:Sel01Tweaker.DryRun) { Write-Log 'DRYRUN skip backup write' 'INFO'; return }
    $obj = [ordered]@{
        Profile  = $Global:Sel01Tweaker.Profile
        Created  = $Global:Sel01Tweaker.Stamp
        PowerSchemeGuid = $Global:Sel01Tweaker.PowerSchemeGuid   # minted Ultimate-Performance GUID, if any
        RamTask  = $Global:Sel01Tweaker.RamTaskName              # scheduled task name, if created
        Registry = $Global:Sel01Tweaker.Backup
    }
    $obj | ConvertTo-Json -Depth 6 | Set-Content -Path $Global:Sel01Tweaker.BackupFile -Encoding UTF8
    Write-Log "Backup written: $($Global:Sel01Tweaker.BackupFile)" 'OK'
}

function Get-LatestBackup {
    $files = Get-ChildItem -Path $Global:Sel01Tweaker.DataDir -Filter 'backup-*.json' -ErrorAction SilentlyContinue |
             Sort-Object LastWriteTime -Descending
    if (-not $files) { return $null }
    return $files[0].FullName
}

function Invoke-Revert {
    <#  Restores every snapshotted registry value, removes the periodic RAM
        scheduled task, and deletes the minted power scheme.  #>
    param([string]$BackupPath)
    if (-not $BackupPath) { $BackupPath = Get-LatestBackup }
    if (-not $BackupPath -or -not (Test-Path $BackupPath)) {
        Write-Log 'No backup file found - nothing to revert.' 'ERROR'
        return
    }
    Write-Log "Reverting from $BackupPath" 'STEP'
    $data = Get-Content -Path $BackupPath -Raw | ConvertFrom-Json

    foreach ($entry in $data.Registry) {
        try {
            if ($entry.Existed) {
                $kind = if ($entry.OldType) { $entry.OldType } else { 'String' }
                $val  = $entry.OldValue
                if ($kind -eq 'Binary' -and $val) { $val = [byte[]]($val | ForEach-Object { [byte]$_ }) }
                if (-not (Test-Path $entry.Path)) { New-Item -Path $entry.Path -Force | Out-Null }
                New-ItemProperty -Path $entry.Path -Name $entry.Name -PropertyType $kind -Value $val -Force | Out-Null
                Write-Log "restored $($entry.Path)\$($entry.Name)" 'INFO'
            } else {
                # Value did not exist before -> remove what we added.
                if (Test-Path $entry.Path) {
                    Remove-ItemProperty -Path $entry.Path -Name $entry.Name -Force -ErrorAction SilentlyContinue
                    Write-Log "removed added $($entry.Path)\$($entry.Name)" 'INFO'
                }
            }
        } catch {
            Write-Log "revert failed for $($entry.Path)\$($entry.Name): $($_.Exception.Message)" 'WARN'
        }
    }

    if ($data.RamTask) {
        try {
            schtasks /Delete /TN $data.RamTask /F 2>$null | Out-Null
            Write-Log "removed scheduled task $($data.RamTask)" 'INFO'
        } catch { Write-Log "task removal failed: $($_.Exception.Message)" 'WARN' }
    }

    if ($data.PowerSchemeGuid) {
        try {
            powercfg /setactive SCHEME_BALANCED 2>$null | Out-Null
            powercfg /delete $data.PowerSchemeGuid 2>$null | Out-Null
            Write-Log "removed power scheme $($data.PowerSchemeGuid), reset to Balanced" 'INFO'
        } catch { Write-Log "power scheme revert failed: $($_.Exception.Message)" 'WARN' }
    }

    Broadcast-SettingChange
    Write-Log 'Revert complete. A sign-out / reboot finalises all changes.' 'OK'
    Write-Log 'Note: apps removed by debloat are NOT reinstalled by revert (use winget/Store).' 'WARN'
}


# ----- bundled: 01-Debloat.ps1 -----
# ============================================================================
#  Module 01 - Debloat  (orchestrates Raphire/Win11Debloat, MIT)
#  Downloads and runs the upstream script silently. Params are passed as a
#  hashtable (named/splatted) so switches bind reliably. Win11Debloat itself
#  supports Windows 10 and 11. Skipped when offline or -SkipDebloat.
# ============================================================================

function Invoke-Module-Debloat {
    Write-Log '=== Module: Debloat (Win11Debloat) ===' 'STEP'

    $url = 'https://debloat.raphi.re/'   # official redirect to latest Win11Debloat.ps1

    # Shared across both profiles.
    $params = @{
        RemoveApps             = $true
        DisableTelemetry       = $true
        DisableBing            = $true
        DisableSuggestions     = $true
        DisableLockscreenTips  = $true
        DisableSettingsHome    = $true
        DisableSettings365Ads  = $true
        RevertContextMenu      = $true
        DisableMouseAcceleration = $true
        ShowKnownFileExt       = $true
        Silent                 = $true
    }

    # Clean = more aggressive. Gaming keeps gaming apps + Game Bar (handled in 06).
    if ($Global:Sel01Tweaker.Profile -eq 'Clean') {
        $params += @{
            RemoveGamingApps    = $true
            DisableWidgets      = $true
            DisableCopilot      = $true
            DisableRecall       = $true
            DisableChat         = $true
            DisableDesktopSpotlight = $true
        }
    }

    Invoke-Remote -Name 'Win11Debloat' -Url $url -Params $params
}


# ----- bundled: 02-RemoveAI.ps1 -----
# ============================================================================
#  Module 02 - RemoveAI  (orchestrates zoicware/RemoveWindowsAI, MIT)
#  Params passed as a hashtable so -nonInteractive binds as a switch and
#  -Options passes as a real string[] (each element validated by the script's
#  ValidateSet). Gaming = lighter option set, Clean = -AllOptions.
#  Recall is Win11-only; the script handles missing components gracefully, so
#  it is safe to run on Windows 10 too (Copilot exists there as well).
# ============================================================================

function Invoke-Module-RemoveAI {
    Write-Log '=== Module: Remove Windows AI ===' 'STEP'

    $url = 'https://raw.githubusercontent.com/zoicware/RemoveWindowsAI/main/RemoveWindowsAi.ps1'

    if ($Global:Sel01Tweaker.Profile -eq 'Clean') {
        $params = @{ nonInteractive = $true; AllOptions = $true }
    } else {
        # Gaming: strip Copilot/Recall + re-add protection, skip the heaviest
        # CBS/file surgery to keep the run fast and low-risk.
        $params = @{
            nonInteractive = $true
            Options = @(
                'DisableRegKeys',
                'PreventAIPackageReinstall',
                'DisableCopilotPolicies',
                'RemoveAppxPackages',
                'RemoveRecallFeature',
                'RemoveWindowsAITasks',
                'UpdateCleanupCheck'
            )
        }
    }

    Invoke-Remote -Name 'RemoveWindowsAI' -Url $url -Params $params
}


# ----- bundled: 03-WinutilTweaks.ps1 -----
# ============================================================================
#  Module 03 - Winutil Tweaks  (NATIVE reimplementation)
#  winutil (ChrisTitusTech, MIT) has no real headless apply in the current
#  release, so the relevant "Essential Tweaks" are reimplemented here directly
#  from the declarative registry / service / scheduled-task data in its
#  config/tweaks.json. Every change flows through Set-Reg -> snapshot -> revert.
# ============================================================================

function Invoke-Module-WinutilTweaks {
    Write-Log '=== Module: Winutil Essential Tweaks (native) ===' 'STEP'

    $clean = ($Global:Sel01Tweaker.Profile -eq 'Clean')

    # --- Telemetry --------------------------------------------------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\DataCollection' 'AllowTelemetry' DWord 0 -Note 'Telemetry off'
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\DataCollection' 'AllowTelemetry' DWord 0
    Set-ServiceStart 'DiagTrack' Disabled -Note 'DiagTrack (Connected User Experiences) disabled'
    Set-ServiceStart 'dmwappushservice' Disabled

    # --- Activity history / timeline -------------------------------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' 'EnableActivityFeed' DWord 0 -Note 'Activity history off'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' 'PublishUserActivities' DWord 0
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' 'UploadUserActivities' DWord 0

    # --- Consumer features / suggested content ---------------------------
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent' 'DisableWindowsConsumerFeatures' DWord 1 -Note 'Consumer features off'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent' 'DisableSoftLanding' DWord 1

    # --- Advertising ID / tailored experiences (per-user) ----------------
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\AdvertisingInfo' 'Enabled' DWord 0 -Note 'Advertising ID off'
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Privacy' 'TailoredExperiencesWithDiagnosticDataEnabled' DWord 0

    # --- Content Delivery Manager (suggestions/auto-install ads) ----------
    $cdm = 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\ContentDeliveryManager'
    foreach ($v in 'SilentInstalledAppsEnabled','SystemPaneSuggestionsEnabled','SoftLandingEnabled',
                    'SubscribedContent-338388Enabled','SubscribedContent-338389Enabled',
                    'SubscribedContent-353698Enabled','PreInstalledAppsEnabled','OemPreInstalledAppsEnabled') {
        Set-Reg $cdm $v DWord 0
    }
    Add-Change 'Start/lockscreen suggestions off'

    # --- Location ---------------------------------------------------------
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\CapabilityAccessManager\ConsentStore\location' 'Value' String 'Deny' -Note 'Location access denied'

    # --- Delivery Optimization (P2P update sharing) ----------------------
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\DeliveryOptimization\Config' 'DODownloadMode' DWord 0 -Note 'Delivery Optimization P2P off'
    Set-ServiceStart 'DoSvc' Manual

    # --- Wi-Fi Sense ------------------------------------------------------
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\PolicyManager\default\WiFi\AllowWiFiHotSpotReporting' 'value' DWord 0
    Set-Reg 'HKLM:\SOFTWARE\Microsoft\PolicyManager\default\WiFi\AllowAutoConnectToWiFiSenseHotspots' 'value' DWord 0

    # --- Show file extensions + hidden files (QoL) -----------------------
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced' 'HideFileExt' DWord 0 -Note 'File extensions shown'

    # ---------------------------------------------------------------------
    #  Clean-profile-only, more aggressive trimming.
    # ---------------------------------------------------------------------
    if ($clean) {
        Write-Log 'Clean profile: extra service trim + telemetry tasks' 'INFO'

        # Background apps off (global, per-user) + policy
        Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\BackgroundAccessApplications' 'GlobalUserDisabled' DWord 1 -Note 'Background apps off'
        Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\AppPrivacy' 'LetAppsRunInBackground' DWord 2

        # Services to Manual (safe, reversible set from winutil)
        foreach ($svc in 'SysMain','MapsBroker','RetailDemo','WSearch','PcaSvc','RemoteRegistry') {
            Set-ServiceStart $svc Manual
        }

        # Disable known telemetry scheduled tasks (revert does NOT re-enable; noted in README)
        $tasks = @(
            '\Microsoft\Windows\Application Experience\Microsoft Compatibility Appraiser',
            '\Microsoft\Windows\Application Experience\ProgramDataUpdater',
            '\Microsoft\Windows\Autochk\Proxy',
            '\Microsoft\Windows\Customer Experience Improvement Program\Consolidator',
            '\Microsoft\Windows\Customer Experience Improvement Program\UsbCeip',
            '\Microsoft\Windows\DiskDiagnostic\Microsoft-Windows-DiskDiagnosticDataCollector'
        )
        foreach ($t in $tasks) {
            if ($Global:Sel01Tweaker.DryRun) { Write-Log "DRYRUN disable task: $t" 'INFO'; continue }
            schtasks /Change /TN $t /Disable 2>$null | Out-Null
        }
        Add-Change 'Telemetry scheduled tasks disabled'

        # Disable hibernation (frees disk; also kills Fast Startup)
        if (-not $Global:Sel01Tweaker.DryRun) { powercfg /hibernate off 2>$null | Out-Null }
        Add-Change 'Hibernation off'
    }
}


# ----- bundled: 04-Performance.ps1 -----
# ============================================================================
#  Module 04 - Performance / Visual Effects  (NATIVE)
#  Replicates the "Adjust for best performance" custom Performance Options
#  state, keeping three effects ON:
#    - Show window contents while dragging  (DragFullWindows = 1)
#    - Smooth edges of screen fonts         (FontSmoothing  = 2)
#    - Show thumbnails instead of icons     (IconsOnly      = 0)
#  Plus transparency/animation off, snappier menus, no startup delay.
# ============================================================================

function Invoke-Module-Performance {
    Write-Log '=== Module: Performance / Visual Effects (native) ===' 'STEP'

    $desktop  = 'HKCU:\Control Panel\Desktop'
    $advanced = 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Advanced'
    $visualfx = 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\VisualEffects'

    # Custom visual-effects mode.
    Set-Reg $visualfx 'VisualFXSetting' DWord 3 -Note 'Visual Effects: Custom (best performance + 3 kept)'

    # The "best performance" preferences mask (animations/fades/shadows off).
    Set-Reg $desktop 'UserPreferencesMask' Binary (Build-PreferencesMask)

    # --- The three effects we KEEP ON ------------------------------------
    Set-Reg $desktop  'DragFullWindows' String '1'   -Note 'Keep: window contents while dragging'
    Set-Reg $desktop  'FontSmoothing'   String '2'   -Note 'Keep: smooth screen fonts (ClearType)'
    Set-Reg $advanced 'IconsOnly'       DWord  0     -Note 'Keep: thumbnails instead of icons'

    # --- Effects we turn OFF ---------------------------------------------
    Set-Reg $advanced 'ListviewShadow'      DWord 0
    Set-Reg $advanced 'ListviewAlphaSelect' DWord 0
    Set-Reg $advanced 'TaskbarAnimations'   DWord 0
    Set-Reg $desktop  'MenuShowDelay'       String '0' -Note 'Menu show delay -> 0ms'

    # Window minimize/maximize animation off (accessibility-honored value).
    Set-Reg "$desktop\WindowMetrics" 'MinAnimate' String '0'

    # --- Transparency off -------------------------------------------------
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Themes\Personalize' 'EnableTransparency' DWord 0 -Note 'Transparency off'

    # --- Remove app startup delay ----------------------------------------
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Serialize' 'StartupDelayInMSec' DWord 0 -Note 'Startup app delay -> 0'

    # Optional: disable mouse acceleration (1:1 input). Applied in both profiles
    # since it never hurts; revertable like everything else.
    Set-Reg 'HKCU:\Control Panel\Mouse' 'MouseSpeed'      String '0' -Note 'Mouse acceleration off'
    Set-Reg 'HKCU:\Control Panel\Mouse' 'MouseThreshold1' String '0'
    Set-Reg 'HKCU:\Control Panel\Mouse' 'MouseThreshold2' String '0'
}


# ----- bundled: 05-PowerPlan.ps1 -----
# ============================================================================
#  Module 05 - Power Plan  (Ultimate Performance)
#  powercfg -duplicatescheme mints a NEW GUID each time; we capture it from the
#  command output and set it active. The minted GUID is stored in state so
#  -Revert can delete it and restore Balanced.
# ============================================================================

function Invoke-Module-PowerPlan {
    Write-Log '=== Module: Power Plan (Ultimate Performance) ===' 'STEP'

    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log 'DRYRUN: would duplicate + activate Ultimate Performance plan' 'INFO'
        return
    }

    $template = 'e9a42b02-d5df-448d-aa00-03f14749eb61'   # built-in Ultimate Performance template

    try {
        # If an Ultimate Performance plan already exists, reuse it.
        $existing = powercfg /list 2>$null | Select-String -Pattern 'Ultimate Performance|Ultimative Leistung'
        if ($existing) {
            $guid = ([regex]'([0-9a-fA-F-]{36})').Match($existing[0].ToString()).Value
            Write-Log "Existing Ultimate Performance plan found: $guid" 'INFO'
        } else {
            $out = powercfg -duplicatescheme $template 2>$null
            $guid = ([regex]'([0-9a-fA-F-]{36})').Match(($out -join ' ')).Value
            if ($guid) { $Global:Sel01Tweaker.PowerSchemeGuid = $guid }   # only mark for deletion if WE minted it
            Write-Log "Minted Ultimate Performance plan: $guid" 'INFO'
        }

        if ($guid) {
            powercfg /setactive $guid 2>$null | Out-Null
            Write-Log 'Ultimate Performance plan active' 'OK'
            Add-Change 'Power plan: Ultimate Performance'
        } else {
            Write-Log 'Could not determine power scheme GUID; leaving plan unchanged' 'WARN'
        }
    } catch {
        Write-Log "Power plan setup failed: $($_.Exception.Message)" 'WARN'
    }
}


# ----- bundled: 06-Gaming.ps1 -----
# ============================================================================
#  Module 06 - Gaming  (profile-gated)
#  GameDVR / background capture is disabled in BOTH profiles (pure overhead).
#  Game Mode + Hardware-accelerated GPU Scheduling (HAGS) are kept ON for the
#  Gaming profile (they help gaming) and turned OFF for the Clean profile.
#  HAGS needs WDDM 2.7+ driver and a reboot to take effect.
# ============================================================================

function Invoke-Module-Gaming {
    Write-Log '=== Module: Gaming tweaks ===' 'STEP'

    $gaming = ($Global:Sel01Tweaker.Profile -eq 'Gaming')

    # --- GameDVR / capture OFF (both profiles) ---------------------------
    Set-Reg 'HKCU:\System\GameConfigStore' 'GameDVR_Enabled' DWord 0 -Note 'GameDVR off'
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\GameDVR' 'AppCaptureEnabled' DWord 0
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\GameDVR' 'AllowGameDVR' DWord 0

    # --- Game Mode + HAGS -------------------------------------------------
    if ($gaming) {
        Set-Reg 'HKCU:\SOFTWARE\Microsoft\GameBar' 'AllowAutoGameMode' DWord 1 -Note 'Game Mode ON (gaming profile)'
        Set-Reg 'HKCU:\SOFTWARE\Microsoft\GameBar' 'AutoGameModeEnabled' DWord 1
        Set-Reg 'HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers' 'HwSchMode' DWord 2 -Note 'HAGS ON (reboot needed)'
        $Global:Sel01Tweaker.RebootNeeded = $true
    } else {
        Set-Reg 'HKCU:\SOFTWARE\Microsoft\GameBar' 'AllowAutoGameMode' DWord 0 -Note 'Game Mode OFF (clean profile)'
        Set-Reg 'HKCU:\SOFTWARE\Microsoft\GameBar' 'AutoGameModeEnabled' DWord 0
        Set-Reg 'HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers' 'HwSchMode' DWord 1 -Note 'HAGS OFF (clean profile)'
        $Global:Sel01Tweaker.RebootNeeded = $true
    }

    # --- Multimedia scheduler: favour foreground game responsiveness -----
    $mm = 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile'
    # 10 (not 0): leaves a small background guarantee so MMCSS audio threads
    # don't get starved (0 causes sound crackle). 10 is the safe gaming value.
    Set-Reg $mm 'SystemResponsiveness' DWord 10 -Note 'System responsiveness favours foreground (audio-safe 10)'
    if ($gaming) {
        Set-Reg $mm 'NetworkThrottlingIndex' DWord 0xffffffff -Note 'Network throttling off'
    }
    $games = "$mm\Tasks\Games"
    Set-Reg $games 'GPU Priority' DWord 8
    Set-Reg $games 'Priority'     DWord 6
    Set-Reg $games 'Scheduling Category' String 'High'
}


# ----- bundled: 07-RamCleaner.ps1 -----
# ============================================================================
#  Module 07 - RAM Cleaner  (NATIVE P/Invoke - NOT WinMemoryCleaner code)
#  WinMemoryCleaner is GPL-3.0, so none of its code is used. This is an
#  independent reimplementation of the same documented Win32 calls:
#    - NtSetSystemInformation(SystemMemoryListInformation) -> purge standby +
#      flush modified page list
#    - EmptyWorkingSet per process
#    - SetSystemFileCacheSize -> trim system file cache
#  Requires SeProfileSingleProcessPrivilege + SeIncreaseQuotaPrivilege, which
#  the embedded type enables. Also optionally registers an hourly clean task.
# ============================================================================

function Initialize-RamCleaner {
    if (([System.Management.Automation.PSTypeName]'Sel01Tweaker.Memory').Type) { return }
    Add-Type -Namespace Sel01Tweaker -Name Memory -UsingNamespace System.Diagnostics -MemberDefinition @'
[StructLayout(LayoutKind.Sequential)]
public struct TokPriv1Luid { public int Count; public long Luid; public int Attr; }

[DllImport("ntdll.dll")]
public static extern uint NtSetSystemInformation(int InfoClass, IntPtr Info, int Length);
[DllImport("advapi32.dll", SetLastError=true)]
public static extern bool OpenProcessToken(IntPtr h, int acc, ref IntPtr phtok);
[DllImport("advapi32.dll", SetLastError=true)]
public static extern bool LookupPrivilegeValue(string host, string name, ref long pluid);
[DllImport("advapi32.dll", SetLastError=true)]
public static extern bool AdjustTokenPrivileges(IntPtr htok, bool disall, ref TokPriv1Luid newst, int len, IntPtr prev, IntPtr relen);
[DllImport("kernel32.dll")] public static extern IntPtr GetCurrentProcess();
[DllImport("psapi.dll")] public static extern int EmptyWorkingSet(IntPtr hwProc);
[DllImport("kernel32.dll", SetLastError=true)]
public static extern bool SetSystemFileCacheSize(IntPtr min, IntPtr max, int flags);

const int SE_PRIVILEGE_ENABLED = 0x00000002;
const int TOKEN_ADJUST = 0x20; const int TOKEN_QUERY = 0x08;
const int SystemMemoryListInformation = 0x50;

static void Enable(string priv) {
    IntPtr tok = IntPtr.Zero;
    OpenProcessToken(GetCurrentProcess(), TOKEN_ADJUST | TOKEN_QUERY, ref tok);
    TokPriv1Luid p; p.Count = 1; p.Luid = 0; p.Attr = SE_PRIVILEGE_ENABLED;
    LookupPrivilegeValue(null, priv, ref p.Luid);
    AdjustTokenPrivileges(tok, false, ref p, 0, IntPtr.Zero, IntPtr.Zero);
}

public static void EnablePrivileges() {
    Enable("SeProfileSingleProcessPrivilege");
    Enable("SeIncreaseQuotaPrivilege");
}

// command: 4 = purge standby list, 3 = flush modified page list, 2 = empty working sets
static uint MemoryCommand(int command) {
    int sz = Marshal.SizeOf(typeof(int));
    IntPtr p = Marshal.AllocHGlobal(sz);
    Marshal.WriteInt32(p, command);
    uint r = NtSetSystemInformation(SystemMemoryListInformation, p, sz);
    Marshal.FreeHGlobal(p);
    return r;
}

public static void PurgeStandbyList()    { MemoryCommand(4); }
public static void FlushModifiedList()   { MemoryCommand(3); }
public static void EmptyAllWorkingSets() {
    foreach (Process proc in Process.GetProcesses()) {
        try { EmptyWorkingSet(proc.Handle); } catch {}
    }
}
public static void TrimFileCache() {
    try { SetSystemFileCacheSize(new IntPtr(-1), new IntPtr(-1), 0); } catch {}
}
'@ -ErrorAction SilentlyContinue
}

function Invoke-RamClean {
    Initialize-RamCleaner
    try {
        [Sel01Tweaker.Memory]::EnablePrivileges()
        [Sel01Tweaker.Memory]::EmptyAllWorkingSets()
        [Sel01Tweaker.Memory]::FlushModifiedList()
        [Sel01Tweaker.Memory]::PurgeStandbyList()
        [Sel01Tweaker.Memory]::TrimFileCache()
        Write-Log 'RAM cleaned (working sets, modified list, standby list, file cache)' 'OK'
    } catch {
        Write-Log "RAM clean failed: $($_.Exception.Message)" 'WARN'
    }
}

function Invoke-Module-RamCleaner {
    param([switch]$NoTask)
    Write-Log '=== Module: RAM Cleaner (native) ===' 'STEP'

    if ($Global:Sel01Tweaker.DryRun) {
        Write-Log 'DRYRUN: would run one-shot RAM clean + register hourly task' 'INFO'
        return
    }

    # One-shot clean now.
    Invoke-RamClean

    if ($NoTask) { Write-Log 'Skipping periodic task (-NoRamTask)' 'INFO'; return }

    # Drop a standalone cleaner script + register an hourly scheduled task.
    $helper = Join-Path $Global:Sel01Tweaker.DataDir 'Sel01Tweaker-RamClean.ps1'
    $helperBody = @'
Add-Type -Namespace Sel01Tweaker -Name Memory -UsingNamespace System.Diagnostics -MemberDefinition @"
[StructLayout(LayoutKind.Sequential)] public struct TokPriv1Luid { public int Count; public long Luid; public int Attr; }
[DllImport("ntdll.dll")] public static extern uint NtSetSystemInformation(int c, IntPtr i, int l);
[DllImport("advapi32.dll", SetLastError=true)] public static extern bool OpenProcessToken(IntPtr h,int a,ref IntPtr t);
[DllImport("advapi32.dll", SetLastError=true)] public static extern bool LookupPrivilegeValue(string h,string n,ref long l);
[DllImport("advapi32.dll", SetLastError=true)] public static extern bool AdjustTokenPrivileges(IntPtr t,bool d,ref TokPriv1Luid n,int len,IntPtr p,IntPtr r);
[DllImport("kernel32.dll")] public static extern IntPtr GetCurrentProcess();
[DllImport("psapi.dll")] public static extern int EmptyWorkingSet(IntPtr h);
[DllImport("kernel32.dll", SetLastError=true)] public static extern bool SetSystemFileCacheSize(IntPtr a,IntPtr b,int f);
static void En(string p){IntPtr t=IntPtr.Zero;OpenProcessToken(GetCurrentProcess(),0x28,ref t);TokPriv1Luid x;x.Count=1;x.Luid=0;x.Attr=2;LookupPrivilegeValue(null,p,ref x.Luid);AdjustTokenPrivileges(t,false,ref x,0,IntPtr.Zero,IntPtr.Zero);}
public static void Run(){En("SeProfileSingleProcessPrivilege");En("SeIncreaseQuotaPrivilege");
foreach(Process pr in Process.GetProcesses()){try{EmptyWorkingSet(pr.Handle);}catch{}}
int sz=Marshal.SizeOf(typeof(int));foreach(int c in new int[]{3,4}){IntPtr m=Marshal.AllocHGlobal(sz);Marshal.WriteInt32(m,c);NtSetSystemInformation(0x50,m,sz);Marshal.FreeHGlobal(m);}
try{SetSystemFileCacheSize(new IntPtr(-1),new IntPtr(-1),0);}catch{}}
"@
[Sel01Tweaker.Memory]::Run()
'@
    Set-Content -Path $helper -Value $helperBody -Encoding UTF8

    $taskName = 'Sel01Tweaker-RamCleaner'
    $cmd = "powershell.exe -NoProfile -WindowStyle Hidden -ExecutionPolicy Bypass -File `"$helper`""
    try {
        schtasks /Create /TN $taskName /TR $cmd /SC HOURLY /RL HIGHEST /RU SYSTEM /F 2>$null | Out-Null
        $Global:Sel01Tweaker.RamTaskName = $taskName
        Write-Log "Registered hourly RAM-clean task: $taskName" 'OK'
        Add-Change 'Hourly RAM-clean task installed'
    } catch {
        Write-Log "Could not register RAM task: $($_.Exception.Message)" 'WARN'
    }
}


# ----- bundled: 08-FiveM.ps1 -----
# ============================================================================
#  Module 08 - FiveM  (Gaming profile only)
#  ONLY safe, reversible, FiveM-relevant tweaks. Every write goes through
#  Set-Reg so -Revert can undo it. Deliberately EXCLUDES the popular-but-harmful
#  "hitreg" tweaks (SystemResponsiveness=0, Win32PrioritySeparation, QoS/Pacer
#  disable, fixed TcpWindowSize, MouseSensitivity override, WaitToKillAppTimeout,
#  TdrLevel=0, large pages, page-file/service kills) — see PROGRESS.md notes.
#
#  Honest scope note: FiveM gameplay traffic is UDP; the TCP Nagle/ACK tweaks
#  below only help the connection/handshake/download path, NOT in-game ping.
# ============================================================================

function Get-FiveMExePaths {
    # Returns full paths of FiveM executables that actually exist on this box.
    $found = [System.Collections.Generic.List[string]]::new()
    $base = Join-Path $env:LOCALAPPDATA 'FiveM'
    $cand = @(Join-Path $base 'FiveM.exe')
    if (Test-Path $base) {
        # FiveM_GTAProcess.exe lives somewhere under the FiveM app dir; find it.
        Get-ChildItem -Path $base -Filter 'FiveM_GTAProcess.exe' -Recurse -ErrorAction SilentlyContinue |
            Select-Object -First 1 -ExpandProperty FullName | ForEach-Object { $cand += $_ }
    }
    foreach ($p in $cand) { if (Test-Path $p) { $found.Add($p) | Out-Null } }
    return $found
}

function Get-ActiveInterfaceGuids {
    # GUIDs of UP adapters that own a default route (the real internet NIC(s)).
    try {
        return (Get-NetIPConfiguration -ErrorAction Stop |
            Where-Object { $_.IPv4DefaultGateway -and $_.NetAdapter.Status -eq 'Up' } |
            ForEach-Object { $_.NetAdapter.InterfaceGuid } | Where-Object { $_ })
    } catch { return @() }
}

function Invoke-Module-FiveM {
    Write-Log '=== Module: FiveM tweaks (safe, Gaming only) ===' 'STEP'

    if ($Global:Sel01Tweaker.Profile -ne 'Gaming') {
        Write-Log 'FiveM module runs only in Gaming profile - skipped.' 'INFO'
        return
    }

    # --- 1) GPU TDR delay: prevent FiveM streaming GPU-reset crashes ------
    # Raise the GPU "hung" timeout from 2s to 8s. NOT TdrLevel=0 (that would
    # remove crash recovery entirely). System-wide but safe + reversible.
    Set-Reg 'HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers' 'TdrDelay' DWord 8 -Note 'GPU TdrDelay 8s (FiveM crash guard)'
    $Global:Sel01Tweaker.RebootNeeded = $true

    # --- 2) Persistent process priority: Above Normal (6), never High/Realtime
    foreach ($exe in 'FiveM.exe','FiveM_GTAProcess.exe') {
        $po = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\$exe\PerfOptions"
        Set-Reg $po 'CpuPriorityClass' DWord 6 -Note "$exe -> Above Normal CPU priority"
    }

    # --- 3) Per-app tweaks that need the real exe path --------------------
    $exes = Get-FiveMExePaths
    if ($exes.Count -eq 0) {
        Write-Log 'FiveM install not found in %LOCALAPPDATA%\FiveM - skipping per-app FSO/GPU tweaks.' 'WARN'
    } else {
        foreach ($path in $exes) {
            # 3a) Disable Fullscreen Optimizations per-app (surgical; lower latency)
            Set-Reg 'HKCU:\Software\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Layers' `
                    $path String '~ DISABLEDXMAXIMIZEDWINDOWEDMODE' -Note "FSO off for $(Split-Path $path -Leaf)"
            # 3b) Force High Performance GPU (helps hybrid-graphics laptops; no-op on desktop)
            Set-Reg 'HKCU:\Software\Microsoft\DirectX\UserGpuPreferences' `
                    $path String 'GpuPreference=2;' -Note "High-Perf GPU for $(Split-Path $path -Leaf)"
        }
    }

    # --- 4) Network: Nagle/Delayed-ACK off on the ACTIVE adapter only -----
    # Helps TCP connect/handshake/resource-download path. Per-interface, so
    # revert (delete) restores defaults; does not touch other adapters.
    $guids = Get-ActiveInterfaceGuids
    if (-not $guids) {
        Write-Log 'No active internet adapter found - skipping network tweaks.' 'WARN'
    } else {
        foreach ($g in $guids) {
            $if = "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces\$g"
            Set-Reg $if 'TcpAckFrequency' DWord 1 -Note "Nagle delayed-ACK off ($g)"
            Set-Reg $if 'TcpNoDelay'      DWord 1
        }
        Write-Log 'Network tweaks affect the TCP path only; FiveM gameplay is UDP.' 'INFO'
    }
}


# ----- bundled: 09-Extra.ps1 -----
# ============================================================================
#  Module 09 - Extra  (privacy / QoL, Windows 10 + 11 aware)
#  Safe, reversible additions researched for BOTH OSes. OS-specific bits are
#  gated by $Global:Sel01Tweaker.IsWin11. Everything via Set-Reg (revertable).
#  Deliberately EXCLUDES: ShowSuperHidden, 8.3-name disable, USB-suspend,
#  hibernation-off, HKLM background-app hammer, keyboard repeat, sticky keys,
#  Reserved Storage / Fast Startup (conditional - left to the user).
# ============================================================================

function Invoke-Module-Extra {
    Write-Log '=== Module: Extra privacy / QoL (OS-aware) ===' 'STEP'

    $win11 = $Global:Sel01Tweaker.IsWin11
    $adv   = 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced'
    $cdm   = 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\ContentDeliveryManager'

    # --- Search / assistants (both OSes) ---------------------------------
    Set-Reg 'HKCU:\SOFTWARE\Policies\Microsoft\Windows\Explorer' 'DisableSearchBoxSuggestions' DWord 1 -Note 'Web/Bing results off in Start search'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\Windows Search' 'AllowCortana' DWord 0
    Set-Reg 'HKCU:\SOFTWARE\Policies\Microsoft\Windows\WindowsCopilot' 'TurnOffWindowsCopilot' DWord 1 -Note 'Copilot taskbar entry hidden'
    Set-Reg 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsCopilot' 'TurnOffWindowsCopilot' DWord 1

    # --- Explorer QoL -----------------------------------------------------
    Set-Reg $adv 'LaunchTo' DWord 1 -Note 'Explorer opens to This PC'
    Set-Reg 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\NamingTemplates' 'ShortcutNameTemplate' String '"%s.lnk"' -Note 'New shortcuts without "- Shortcut" suffix'
    Set-Reg $adv 'ShowSyncProviderNotifications' DWord 0 -Note 'Explorer ad / OneDrive notifications off'

    # --- Lock-screen tips + Settings suggestions (privacy) ----------------
    Set-Reg $cdm 'RotatingLockScreenOverlayEnabled' DWord 0 -Note 'Lock-screen tips / fun facts off'
    foreach ($v in 'SubscribedContent-338387Enabled','SubscribedContent-338393Enabled',
                    'SubscribedContent-353694Enabled','SubscribedContent-353696Enabled') {
        Set-Reg $cdm $v DWord 0
    }

    # --- Edge background / startup ---------------------------------------
    $edge = 'HKLM:\SOFTWARE\Policies\Microsoft\Edge'
    Set-Reg $edge 'StartupBoostEnabled'   DWord 0 -Note 'Edge startup boost off'
    Set-Reg $edge 'BackgroundModeEnabled' DWord 0 -Note 'Edge background mode off'
    Set-Reg $edge 'HideFirstRunExperience' DWord 1

    # --- Filesystem (SSD-friendly, dev QoL) ------------------------------
    $fs = 'HKLM:\SYSTEM\CurrentControlSet\Control\FileSystem'
    Set-Reg $fs 'NtfsDisableLastAccessUpdate' DWord 0x80000001 -Note 'NTFS last-access updates off (SSD-friendly)'
    Set-Reg $fs 'LongPathsEnabled' DWord 1 -Note 'Long paths (>260 chars) enabled'

    # --- OS-specific ------------------------------------------------------
    if ($win11) {
        Set-Reg $adv 'Start_TrackDocs' DWord 0 -Note 'Recent docs tracking off (Win11)'
        Set-Reg "$adv\TaskbarDeveloperSettings" 'TaskbarEndTask' DWord 1 -Note 'Taskbar right-click End Task (Win11)'
    } else {
        # Older Win10 builds where the policy key above may not cover web search.
        Set-Reg 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Search' 'BingSearchEnabled' DWord 0 -Note 'Bing search off (Win10)'
        Set-Reg 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Search' 'CortanaConsent'    DWord 0
    }
}



# ---------------------------------------------------------------------------
#  Load parts. When bundled into dist\Sel01Tweaker.ps1 the functions already
#  exist, so dot-sourcing is skipped. When running from src\, pull lib+modules.
# ---------------------------------------------------------------------------
if (-not (Get-Command Invoke-Module-Performance -ErrorAction SilentlyContinue)) {
    $root = $PSScriptRoot
    . (Join-Path $root 'lib\Common.ps1')
    . (Join-Path $root 'lib\Backup.ps1')
    Get-ChildItem (Join-Path $root 'modules') -Filter '*.ps1' | Sort-Object Name | ForEach-Object { . $_.FullName }
}

# ===========================================================================
#  Console UI
# ===========================================================================
function Show-Banner {
    Clear-Host
    Write-Host ''
    Write-Host '   ====================================================' -ForegroundColor DarkCyan
    Write-Host '        ____  ____ _     ___  _      _____         ' -ForegroundColor Cyan
    Write-Host '       / ___|| ___| |   / _ \/ |    |_   _|_      __' -ForegroundColor Cyan
